@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" role="img" aria-label="@Product.Name">
        @Product.Name
    </div>
    <div class="product-info">
        <h4 class="product-name">@Product.Name</h4>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" aria-label="@($"Rating: {Product.Rating:F1} out of 5")">
            @GetStarDisplay()
        </div>
        @if (!Product.InStock)
        {
            <span class="badge-out-of-stock">Out of Stock</span>
        }
        <button class="btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string GetStarDisplay()
    {
        int filled = (int)Math.Round(Product.Rating);
        return new string('★', filled) + new string('☆', 5 - filled);
    }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog

<div class="product-grid">
    @foreach (var product in Products)
    {
        <ProductCard Product="product"
                     OnSelected="OnProductSelected"
                     OnAddToCart="OnAddToCart" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog

<aside class="catalog-filters">
    <h3>Filters</h3>

    <fieldset>
        <legend>Categories</legend>
        @foreach (var category in Categories)
        {
            <label class="filter-checkbox">
                <input type="checkbox"
                       checked="@IsSelected(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                @category
            </label>
        }
    </fieldset>

    <fieldset>
        <legend>Price Range</legend>
        <label>
            Min
            <input type="number" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
        </label>
        <label>
            Max
            <input type="number" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </label>
    </fieldset>

    <fieldset>
        <legend>Availability</legend>
        <label class="filter-checkbox">
            <input type="checkbox"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
            In Stock Only
        </label>
    </fieldset>

    <div class="filter-actions">
        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = new();

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await ApplyFilters();
    }
}

@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog

<div class="catalog-toolbar">
    <div class="toolbar-sort">
        <label for="sort-select">Sort by:</label>
        <select id="sort-select" value="@CurrentSort" @onchange="HandleSortChange">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="toolbar-info">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string CurrentSort { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog

<nav class="catalog-pagination" aria-label="Product pagination">
    <button disabled="@(CurrentPage <= 1)" @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var page = i;
        <button class="@(page == CurrentPage ? "page-btn active" : "page-btn")"
                @onclick="@(() => GoToPage(page))">
            @page
        </button>
    }

    <button disabled="@(CurrentPage >= TotalPages)" @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@namespace sv_e3a5974c670e49fb9304f89abd9938ae.Components.Pages.Catalog
@using sv_e3a5974c670e49fb9304f89abd9938ae
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-layout">
    <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" />

    <main class="catalog-main">
        @if (_loading)
        {
            <div class="catalog-loading">Loading products...</div>
        }
        else if (_error is not null)
        {
            <div class="catalog-error">
                <p>Something went wrong: @_error</p>
                <button @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else
        {
            <CatalogToolbar CurrentSort="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<string> _categories = new();
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalPages = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _totalPages = (int)Math.Ceiling((double)_result.TotalCount / PageSize);
            if (_totalPages < 1) _totalPages = 1;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }
}

