namespace sv_e3a5974c670e49fb9304f89abd9938ae;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

/* Sidebar filters */
.catalog-filters {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    align-self: flex-start;
}

.catalog-filters h3 {
    margin-top: 0;
}

.catalog-filters fieldset {
    border: none;
    padding: 0;
    margin: 0 0 1rem;
}

.catalog-filters legend {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    margin-bottom: 0.3rem;
    cursor: pointer;
}

.catalog-filters input[type="number"] {
    width: 100%;
    padding: 0.3rem;
    margin-top: 0.2rem;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply, .btn-clear {
    padding: 0.5rem 1rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn-apply {
    background-color: #0d6efd;
    color: white;
}

.btn-clear {
    background-color: #6c757d;
    color: white;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.toolbar-sort {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.toolbar-sort select {
    padding: 0.3rem 0.5rem;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 12px rgba(0,0,0,0.12);
}

.product-image {
    background: #e9ecef;
    height: 150px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.3rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: 600;
    color: #198754;
}

.product-rating {
    color: #ffc107;
    margin-bottom: 0.3rem;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    padding: 0.4rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-add-to-cart:disabled {
    background: #adb5bd;
    cursor: not-allowed;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    gap: 0.3rem;
    justify-content: center;
    padding: 1rem 0;
}

.catalog-pagination button {
    padding: 0.4rem 0.8rem;
    border: 1px solid #dee2e6;
    background: white;
    border-radius: 4px;
    cursor: pointer;
}

.catalog-pagination button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.catalog-pagination button.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

/* States */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.catalog-error {
    color: #dc3545;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

