.catalog-main {
    flex: 1;
    min-width: 0;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem;
    background: #f8f9fa;
    border-radius: 4px;
}

.toolbar-sort {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.toolbar-sort select {
    padding: 0.3rem 0.5rem;
}

/* Product grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.product-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.2s;
}

.product-card:hover {
    box-shadow: 0 2px 12px rgba(0,0,0,0.12);
}

.product-image {
    background: #e9ecef;
    height: 150px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.85rem;
    text-align: center;
    padding: 0.5rem;
}

.product-info {
    padding: 0.75rem;
}

.product-name {
    margin: 0 0 0.3rem;
    font-size: 1rem;
}

.product-price {
    margin: 0 0 0.3rem;
    font-weight: 600;
    color: #198754;
}

.product-rating {
    color: #ffc107;
    margin-bottom: 0.3rem;
}

.badge-out-of-stock {
    display: inline-block;
    background: #dc3545;
    color: white;
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    margin-bottom: 0.4rem;
}

.btn-add-to-cart {
    width: 100%;
    padding: 0.4rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-add-to-cart:disabled {
    background: #adb5bd;
    cursor: not-allowed;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    gap: 0.3rem;
    justify-content: center;
    padding: 1rem 0;
}

.catalog-pagination button {
    padding: 0.4rem 0.8rem;
    border: 1px solid #dee2e6;
    background: white;
    border-radius: 4px;
    cursor: pointer;
}

.catalog-pagination button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.catalog-pagination button.active {
    background: #0d6efd;
    color: white;
    border-color: #0d6efd;
}

/* States */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.catalog-error {
    color: #dc3545;
}

.catalog-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

